        private void BuildNpcGateGrudDialogue()
        {
            var g = ScriptableObject.CreateInstance<DialogueGraph>();
            g.conversationId = "npc.gate.grud";
            g.startNodeId = "0";

            g.nodes.Add(new DialogueNode
            {
                id = "0", speaker = "Grud",
                text = "*(A vast half-orc leaning on a shovel, beaming, in a graveyard that is doing record business.)* Beautiful day for it! *(He gestures at the rows of fresh-turned earth like a proud gardener.)* Look at that drainage. Look at that *loam.* You know most folk see a graveyard and think sad thoughts? I see a *neighborhood.* Quiet neighbors. Never complain about the noise. Property values only go up — well. Down. But *up*, spiritually. *(He extends a hand the size of a dinner plate.)* Grud. I plant people. Best in the Gate.",
                autoNextNodeId = "1",
