            });

            g.nodes.Add(new DialogueNode
            {
                id = "1", speaker = "Grud",
                text = "*(He pats a headstone affectionately.)* This here's Old Merrow. Cheated me at dice for thirty years. Now he's under my shovel and I win every game, on account of he can't reach the cup. *(He laughs, then sobers, just slightly.)* Lot of harvest folk coming through lately, though. Them I don't joke about. Them I plant *careful.* A man's got to know which deaths are funny and which are just... Tuesday. *(He brightens again.)* You need planting? You look spry, but I'm a patient man, and I do a discount for repeat customers. ...You being a Returned and all. *(beat)* That were a joke. Mostly.",
                choices = new[]
                {
                    new DialogueChoice { text = "\"How do you stay so cheerful surrounded by all this?\"", nextNodeId = "cheerful" },
                    new DialogueChoice { text = "[INSIGHT 14] \"You're not cheerful. You're *defended*. The jokes are how you survive the careful ones.\"", nextNodeId = "defended", checkAbility = Ability.Wisdom, checkDC = 14, failNodeId = "laugh" },
                    new DialogueChoice { text = "\"The harvest folk — anyone come through you'd want me to know about?\"", nextNodeId = "harvest" },
                    new DialogueChoice { text = "\"Plant me when I'm done, Grud. Loam like that, who could refuse.\"", nextNodeId = "plantme", effects = new[] { new FlagClause { key = "companion.varra.approval", op = FlagOp.AddInt, amount = 2 } } },
                }
            });

            g.nodes.Add(new DialogueNode
            {
                id = "cheerful", speaker = "Grud",
                text = "*(He considers this seriously, leaning on the shovel.)* Way I figure it — somebody's got to be glad to see them. *(He looks out over the rows.)* They come to me on the worst day anybody's having, carried by people too cried-out to speak. And I can be one more grey face doing a grim job, or I can be the big daft fellow who tells them Old Merrow can't reach the dice cup, and gives the children a job holding the marker, and makes the worst day have *one* warm thing in it. *(He shrugs, mountainous.)* Cheerful's not how I feel. Cheerful's the *service.* Anybody can dig a hole. I dig a *kindness.*",
                autoNextNodeId = "close",
                onEnter = new[] { new FlagClause { key = "npc.grud_philosophy", op = FlagOp.SetTrue }, new FlagClause { key = "companion.garrow.approval", op = FlagOp.AddInt, amount = 3 } },
            });

            g.nodes.Add(new DialogueNode
            {
                id = "defended", speaker = "Grud",
                text = "*(The beam falters, and for a moment the half-orc is just tired, the way only the relentlessly cheerful get tired.)* ...You're a sharp one. *(quietly)* Aye. I planted my whole family in a fortnight, in the last bad winter. Eight of them. And I found that if I stopped smiling even once, I'd not get it started again, and then who'd be glad to see the next ones? *(He squares his shoulders, and the beam comes back, but you've seen behind it now.)* So I decided to be glad on purpose. Forever. It's the only fight I know how to keep winning. Don't tell the children. They like Old Merrow's dice story.",
                autoNextNodeId = "close",
                onEnter = new[] { new FlagClause { key = "npc.grud_grief", op = FlagOp.SetTrue }, new FlagClause { key = "companion.garrow.approval", op = FlagOp.AddInt, amount = 4 } },
            });

            g.nodes.Add(new DialogueNode
            {
                id = "harvest", speaker = "Grud",
                text = "*(His face goes still and careful — the planting-careful.)* Aye. One. Young fella, sorted to the Wall, but his sister couldn't afford a Choir burial nor a church one, so she brought him to me with nothing but his name on a scrap. *(He nods at a plain marker.)* I planted him free. Wrote the name myself. *(He looks at you.)* The church says the Faithless don't get markers — that's the *point*, the forgetting. So if you're the sort who pokes the church in the eye, you might tell that girl her brother's got a marker after all. Lula, her name is. Keeps a list of the forgotten. Find her if you've a heart for it.",
                autoNextNodeId = "close",
                onEnter = new[] { new FlagClause { key = "npc.grud_points_to_lula", op = FlagOp.SetTrue }, new FlagClause { key = "sq.lulaslist_hinted", op = FlagOp.SetTrue } },
            });

            g.nodes.Add(new DialogueNode
            {
                id = "plantme", speaker = "Grud",
                text = "*(He roars with delight.)* HA! \"Loam like that, who could refuse!\" *(He claps you on the shoulder, nearly felling you.)* Oh, I *like* you. Tell you what — you die again, you come straight to Grud, no waiting list, premium plot, and I'll cheat Old Merrow out of his dice in your honor. *(He wipes his eyes.)* Spry AND funny. The good ones always plant well. Off you go. Try not to need me too soon.",
                autoNextNodeId = "close",
            });

            g.nodes.Add(new DialogueNode
            {
                id = "laugh", speaker = "Grud",
                text = "*(He just laughs, big and uncomplicated.)* Defended! From a *graveyard!* Friend, the only thing I'm defending is this loam from amateurs. Go on with you.",
                autoNextNodeId = "close",
            });

            g.nodes.Add(new DialogueNode
            {
                id = "close", speaker = "Grud",
                text = "*(He returns to his shovel, whistling something that might be a hymn or might be a drinking song — with Grud, you suspect, there was never much difference.)*",
            });

